The reason your data didn't write to the spreadsheet in the previous attempt is likely because I missed updating the URL in the **Partner** and **Volunteer** components, while only updating it in the Community component.

I have now synchronized **all components** with your new URL: `https://script.google.com/macros/s/AKfycbz7pxlJ0F13vJ9xGMIO_fZjJ4qwX6FA7bsa8y0ses_499DcdZFeu3tp3GK6MO3cfhym/exec`.

### 1. The Correct Google Apps Script (Multi-Tab Version)
Please replace your entire Apps Script with this version. It is specifically built to handle multiple tabs (Community, Partners, etc.) and will create the tabs for you if they don't exist.

```javascript
function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000); // Wait up to 10s

  try {
    var contents = JSON.parse(e.postData.contents);
    var ss = SpreadsheetApp.getActiveSpreadsheet();

    // Get target sheet name from the form, default to 'General'
    var sheetName = contents.sheetName || "General";
    var sheet = ss.getSheetByName(sheetName) || ss.insertSheet(sheetName);

    // If sheet is empty, create headers from the JSON keys
    if (sheet.getLastColumn() === 0) {
      var keys = Object.keys(contents);
      sheet.appendRow(keys);
    }

    // Always read current headers to ensure data aligns with columns correctly
    var headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];

    // Map the incoming data to the existing column headers
    var newRow = headers.map(function(header) {
      return contents[header] !== undefined ? contents[header] : "";
    });

    sheet.appendRow(newRow);

    return ContentService.createTextOutput("Success")
      .setMimeType(ContentService.MimeType.TEXT);

  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.toString())
      .setMimeType(ContentService.MimeType.TEXT);
  } finally {
    lock.releaseLock();
  }
}
```

