// SHEET NAME: Does not matter, the script will create tabs based on your form data.
var SCRIPT_PROP = PropertiesService.getScriptProperties(); 

function setup() {
  var doc = SpreadsheetApp.getActiveSpreadsheet();
  SCRIPT_PROP.setProperty("key", doc.getId());
}

function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000); // Wait up to 10 seconds for concurrent requests

  try {
    var doc = SpreadsheetApp.getActiveSpreadsheet();

    // 1. PARSE DATA (Handles both JSON and standard Form Data)
    var params;
    if (e.postData && e.postData.contents) {
      try {
        params = JSON.parse(e.postData.contents);
      } catch(err) {
        params = e.parameter; // Fallback
      }
    } else {
      params = e.parameter;
    }

    // 2. DETERMINE TAB NAME
    // This comes from the 'sheetName' field in your React App (e.g., "Volunteer", "Community")
    var sheetName = params.sheetName || "General";
    var sheet = doc.getSheetByName(sheetName);

    // 3. CREATE TAB IF MISSING
    if (!sheet) {
      sheet = doc.insertSheet(sheetName);
    }

    // 4. HANDLE HEADERS (Auto-generate if sheet is empty)
    var headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
    var nextRow = sheet.getLastRow() + 1;
    var newRow = [];

    // If the sheet is brand new, write the headers from the incoming keys
    if (headers.length === 0 || (headers.length === 1 && headers[0] === "")) {
      headers = Object.keys(params);
      sheet.getRange(1, 1, 1, headers.length).setValues([headers]);
    }

    // 5. MAP DATA TO HEADERS
    // This ensures data goes into the correct column, even if order changes
    for (var i = 0; i < headers.length; i++) {
      var header = headers[i];
      // Append a single quote ' to force string format (prevents date/number auto-formatting issues)
      var val = params[header];
      newRow.push(val !== undefined ? val : "");
    }

    // 6. WRITE DATA
    if (newRow.length > 0) {
      sheet.getRange(nextRow, 1, 1, newRow.length).setValues([newRow]);
    }

    return ContentService
      .createTextOutput(JSON.stringify({ "result": "success", "row": nextRow }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (e) {
    return ContentService
      .createTextOutput(JSON.stringify({ "result": "error", "error": e.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}
